图论之欧拉回路、差分约束——算法笔记比赛
欧拉回路无向代码1：
void dfs(int x)&#123;	while(f[x]&lt;to[x].size())&#123;		int y=to[x][f[x]].first,idx=to[x][f[x]].second;		f[x]++;		if(!vis[idx])&#123;			vis[idx]=vis[idx^1]=1;			dfs(y);			c[++l]=y;		&#125;	&#125;&#125;
无向代码2：
int x=0,y=0,z=0;for(int i=1;i&lt;=n;++i)&#123;	if(d[i]&amp;1)x=i,++y;&#125;if(y&amp;&amp;y!=2)&#123;	cout&lt;&lt;&quot;Impossible&quot;&lt;&lt;endl;&#125;
有向题目：
#include&lt;bits/stdc++.h&gt;using namespace std;int n,m,d[100005],c[100005],f[100005]/*表示遍历到第几个点*/;vector&lt;int&gt;a[100005];stack&lt;int&gt;st;void dfs(int x)&#123;	int l=0;	while(f[x]&lt;a[x].size())&#123;		int y=a[x][f[x]];		f[x]++;		dfs(y);		c[++l]=y;	&#125;	st.push(x);&#125;int main()&#123;	cin&gt;&gt;n&gt;&gt;m;	int ind[100005],outd[100005],u,v;	for(int i=1;i&lt;=m;++i)&#123;		cin&gt;&gt;u&gt;&gt;v;		a[u].push_back(v);		ind[v]++,outd[u]++;	&#125;	for(int i=1;i&lt;=n;++i)sort(a[i].begin(),a[i].end());	int x=1,y=0,z=0;	for(int i=1;i&lt;=n;++i)&#123;		if(ind[i]+1==outd[i])x=i,++y;		if(ind[i]!=outd[i])++z;	&#125;	if(!((y==1&amp;&amp;z==2)||!z))&#123;		cout&lt;&lt;&quot;No&quot;&lt;&lt;endl;		return 0;	&#125;	dfs(x);	while(!st.empty())&#123;		cout&lt;&lt;st.top()&lt;&lt;&quot; &quot;;		st.pop();	&#125;	return 0;&#125;
差分约束Bellman_Ford：
void Bellman_Ford(int n)&#123;	auto relax=[&amp;]()&#123;		bool f=0;		for(int i=1;i&lt;=n;++i)&#123;			for(auto k:to[i])&#123;				if(ans[i]&gt;ans[k.first]+k.second)&#123;					ans[i]=min(ans[i],ans[k.first]+k.second),f=1;				&#125;			&#125;		&#125;		return f;	&#125;;	for(int i=0;i&lt;n-1;++i)relax();	if(relax())cout&lt;&lt;&quot;NO&quot;;	else for(int i=1;i&lt;=n;++i)cout&lt;&lt;ans[i]&lt;&lt;&quot; &quot;;&#125;
完整题目：
#include&lt;bits/stdc++.h&gt;using namespace std;int ans[5005];vector&lt;pair&lt;int,int&gt;&gt;to[5005];void Bellman_Ford(int n)&#123;	auto relax=[&amp;]()&#123;		bool f=0;		for(int i=1;i&lt;=n;++i)&#123;			for(auto k:to[i])&#123;				if(ans[i]&gt;ans[k.first]+k.second)&#123;					ans[i]=min(ans[i],ans[k.first]+k.second),f=1;				&#125;			&#125;		&#125;		return f;	&#125;;	for(int i=0;i&lt;n-1;++i)relax();	if(relax())cout&lt;&lt;&quot;NO&quot;;	else for(int i=1;i&lt;=n;++i)cout&lt;&lt;ans[i]&lt;&lt;&quot; &quot;;&#125;int n,m,c1,c2,y;int main() &#123;	cin&gt;&gt;n&gt;&gt;m;	fill(ans,ans+n+1,0);	for(int i=1;i&lt;=m;++i)&#123;		cin&gt;&gt;c1&gt;&gt;c2&gt;&gt;y;		to[c1].push_back(&#123;c2,y&#125;);	&#125;	Bellman_Ford(n);    return 0;&#125;

  详情

设计状态：用 $dp_{u,0/1}$ 表示以 $u$ 为根的子树的最大快乐指数。
答案：$\max{dp_{root,1},dp_{root,0}}$。





P1352 没有上司的舞会若如图所示，当前 dfs 至点 $u$，则转移方程如下：$$dp_{u,0}\leftarrow dp_{u,0}+\max(dp_{v,0},dp_{v,1})$$$$dp_{u,1}\leftarrow dp_{u,1}+dp_{v,0}$$

所以可以写出以下代码：
#include&lt;bits/stdc++.h&gt;using namespace std;int n,r[6005],in[6005],rt,dp[6005][2];vector&lt;int&gt;g[6005];void dfs(int u)&#123;    for(int v:g[u])&#123;        dfs(v);        dp[u][0]+=max(dp[v][0],dp[v][1]);        dp[u][1]+=dp[v][0];    &#125;    dp[u][1]+=r[u];&#125;int main()&#123;    cin&gt;&gt;n;    for(int i=1;i&lt;=n;++i)&#123;        cin&gt;&gt;r[i];    &#125;    for(int i=1;i&lt;n;++i)&#123;        int u,v;        cin&gt;&gt;u&gt;&gt;v;        g[v].push_back(u);        in[u]=1;    &#125;    for(int i=1;i&lt;=n;++i)&#123;        if(!in[i])&#123;            rt=i;            break;        &#125;    &#125;    dfs(rt);    cout&lt;&lt;max(dp[rt][0],dp[rt][1];&#125;

P2016 [SEERC 2000] 战略游戏在开始是初始化一下 $dp_{u,0/1}$ 即可。

  为什么不需要初始化 $dp$ 为无穷大

在 dfs 中会遍历每个子节点，所以初始化子节点即可，树形 DP 无需 memset $dp$ 数组。





#include&lt;bits/stdc++.h&gt;using namespace std;int n,in[5005],dp[5005][2],rt;vector&lt;int&gt;g[5005];void dfs(int u)&#123;    dp[u][0]=0;    dp[u][1]=1;    for(int v:g[u])&#123;        dfs(v);        dp[u][0]+=dp[v][1];        dp[u][1]+=min(dp[v][0],dp[v][1]);    &#125;&#125;int main()&#123;    cin&gt;&gt;n;    for(int i=1;i&lt;=n;++i)&#123;        int u,k,v;        cin&gt;&gt;u&gt;&gt;k;        u++;        for(int j=1;j&lt;=k;++j)&#123;            cin&gt;&gt;v;            v++;            g[u].push_back(v);            in[v]=1;        &#125;    &#125;    for(int i=1;i&lt;=n;++i)&#123;        if(!in[i])&#123;            rt=i;            break;        &#125;    &#125;    dfs(rt);    cout&lt;&lt;min(dp[rt][0],dp[rt][1]);    return 0;&#125;

P1122 最大子树和
#include&lt;bits/stdc++.h&gt;using namespace std;int n,a[16005],dp[16005],ans=INT_MIN;vector&lt;int&gt;g[16005];void dfs(int u,int fa)&#123;    dp[u]=a[u];    for(int v:g[u])&#123;        if(v!=fa)&#123;            dfs(v,u);            dp[u]+=max(0,dp[v]);        &#125;    &#125;&#125;int main()&#123;    cin&gt;&gt;n;    for(int i=1;i&lt;=n;++i)cin&gt;&gt;a[i];    for(int i=1;i&lt;n;++i)&#123;        int u,v;        cin&gt;&gt;u&gt;&gt;v;        g[u].push_back(v);        g[v].push_back(u);    &#125;    dfs(1,0);    for(int i=1;i&lt;=n;++i)&#123;        ans=max(dp[i],ans);    &#125;    cout&lt;&lt;ans;    return 0;&#125;

P2585 [ZJOI2006] 三色二叉树

A. 字符串按照题意模拟即可，如果想要省掉代码量可以开个 std::vector&lt;std::pair&lt;char, int&gt;&gt; ve(n) 前一个记录字符，后一个记录当前的下标，直接进行升序排序，然后直接从k+1个开始输出。 提供排序的代码。
void clearlove13(void)&#123;    int n, k;    std::cin &gt;&gt; n &gt;&gt; k;    std::string s;    std::cin &gt;&gt; s;    std::vector&lt;std::pair&lt;char, int&gt;&gt; ve(n);    for (int i = 0; i &lt; n; i++) &#123;        ve[i] = std::make_pair(s[i], i);    &#125;    std::sort(ve.begin(), ve.end());    std::vector&lt;std::pair&lt;char, int&gt;&gt; ans;    ans.reserve(n);    for (int i = k; i &lt; n; i++) &#123;        ans.push_back(&#123;ve[i].first, ve[i].second&#125;);    &#125;    std::sort(ans.begin(), ans.end(), [&amp;](auto &amp; a, auto &amp; b) &#123;        return a.second &lt; b.second;    &#125;);    for (auto &amp;[x, y] : ans) &#123;        std::cout &lt;&lt; x;    &#125;&#125;

B. 价格跨度题意大概就是求该 $a_i$ 前面第一个大于该 $a_i$ 的位置，从题目数据可得知，此题我们需要使用 $\mathcal{O(n)}$ 复杂度来写这道题，思考一下可以使用单调栈来实现，只需要等效思想来写即可。
void clearlove13(void)&#123;    int n;    std::cin &gt;&gt; n;    std::vector&lt;int&gt; a(n + 1);    for (int i = 1; i &lt;= n; i++) &#123;        std::cin &gt;&gt; a[i];    &#125;    std::vector&lt;int&gt;st;    std::vector&lt;int&gt; ans(n + 1);    st.reserve(n + 1);     for (int i = 1; i &lt;= n; i++) &#123;        while (!st.empty() &amp;&amp; a[st.back()] &lt;= a[i]) &#123;            st.pop_back();        &#125;        if (st.empty()) &#123;            ans[i] = i;        &#125; else &#123;            ans[i] = i - st.back();        &#125;        st.push_back(i);    &#125;     for (int i = 1; i &lt;= n; i++) &#123;        std::cout &lt;&lt; ans[i];        if (i != n) std::cout &lt;&lt; &#x27; &#x27;;    &#125;&#125;

C. 斐波那契数事实上题目已经告诉你了做法直接模拟即可。
i64 a[51];void clearlove13(void)&#123;    int n;    std::cin &gt;&gt; n;    std::cout &lt;&lt; a[n] &lt;&lt; &#x27;\n&#x27;;&#125;int main(void)&#123;    std::ios::sync_with_stdio(false);    std::cin.tie(nullptr);    a[1] = 1;    a[0] = 1;    for (int i = 2; i &lt;= 50; i++) &#123;        a[i] = a[i - 1] + a[i - 2];    &#125;     int cas = 1;    std::cin &gt;&gt; cas;    while (cas--) clearlove13();    return 0;&#125;

D. 回收礼物设 $f(x\to y)$ 是以 $1$ 为根 ，求x到y的树上最小路径 我们先了解题意，就可以明白是需要求形如 $f(1\to 2)+f(2\to 3)+f(3\to {\dots})+f({\dots}\to 2)$ 这么一个式子，那么我们应该怎么快速去求树上最短路径呢？引入lca求最近公共祖先，有一个小trick就是我们 所以我们就先求出到两个点的深度之和再减去公共祖先的深度就可以写出这道题了。
struct LCA &#123;    int n, lg;    std::vector&lt;std::vector&lt;int&gt;&gt; up;    std::vector&lt;int&gt; depth, tin, tout;    int timer = 0;     LCA(std::vector&lt;std::vector&lt;int&gt;&gt;&amp; ed, int root = 0) &#123;        n = int(ed.size());        lg = std::__lg(n) + 1;        up.assign(n, std::vector&lt;int&gt;(lg));        depth.assign(n, 0);        tin.resize(n), tout.resize(n);        auto dfs = [&amp;](auto self, int u, int p) -&gt; void &#123;            tin[u] = timer++;            up[u][0] = p;            for (int i = 1; i &lt; lg; ++i) up[u][i] = up[up[u][i - 1]][i - 1];            for (int v : ed[u]) &#123;                if (v == p) continue;                depth[v] = depth[u] + 1;                self(self, v, u);            &#125;            tout[u] = timer++;        &#125;;        dfs(dfs, root, root);    &#125;     bool is_ancestor(int u, int v) &#123;        return tin[u] &lt;= tin[v] &amp;&amp; tout[v] &lt;= tout[u];    &#125;     int get_lca(int u, int v) &#123;        if (is_ancestor(u, v)) return u;        if (is_ancestor(v, u)) return v;        for (int i = lg - 1; i &gt;= 0; --i)            if (!is_ancestor(up[u][i], v)) u = up[u][i];        return up[u][0];    &#125;     std::vector&lt;int&gt; get_path(int u, int v) &#123;        int w = get_lca(u, v);        std::vector&lt;int&gt; up_path, down_path;        while (u != w) &#123;            up_path.push_back(u);            u = up[u][0];        &#125;        up_path.push_back(w);        while (v != w) &#123;            down_path.push_back(v);            v = up[v][0];        &#125;        std::reverse(down_path.begin(), down_path.end());        up_path.insert(up_path.end(), down_path.begin(), down_path.end());        return up_path;    &#125;&#125;; void clearlove13() &#123;    constexpr int lg = 20;    int n, q, rt;    std::cin &gt;&gt; n &gt;&gt; q ;    rt = 1;    std::vector&lt;std::vector&lt;int&gt;&gt; g(n + 1);    std::vector&lt;int&gt;ch(q);    for (int i = 2; i &lt;= n; i++) &#123;        int u;        std::cin &gt;&gt; u;        g[u].push_back(i);        g[i].push_back(u);    &#125;     std::vector&lt;int&gt; dep(n + 1);    std::vector&lt;std::array&lt;int, lg&gt;&gt; up(n + 1);    for (int i = 1; i &lt;= n; i++) &#123;        std::fill(up[i].begin(), up[i].end(), -1);    &#125;     auto dfs = [&amp;](auto self, int u, int fa) -&gt; void &#123;        up[u][0] = fa;        for (int i = 1; i &lt; lg; i++) &#123;            if (up[u][i - 1] != -1) &#123;                up[u][i] = up[up[u][i - 1]][i - 1];            &#125;        &#125;        for (int v : g[u]) &#123;            if (v != fa) &#123;                dep[v] = dep[u] + 1;                self(self, v, u);            &#125;        &#125;    &#125;;     dfs(dfs, rt, -1);     auto lca = [&amp;](i64 u, i64 v) -&gt; int &#123;        if (dep[u] &lt; dep[v]) std::swap(u, v);        i64 d = dep[u] - dep[v];        for (int i = 0; i &lt; lg; i++) &#123;            if (d &gt;&gt; i &amp; 1) u = up[u][i];        &#125;        if (u == v) return u;        for (int i = lg - 1; i &gt;= 0; i--) &#123;            if (up[u][i] != up[v][i]) &#123;                u = up[u][i];                v = up[v][i];            &#125;        &#125;        return up[u][0];    &#125;;     auto dist = [&amp;](i64 u, i64 v) -&gt; int &#123;        i64 l = lca(u, v);        return dep[u] + dep[v] - 2 * dep[l];    &#125;;     for (auto &amp;i : ch) &#123;        std::cin &gt;&gt; i;    &#125;    i64 ans = dist(1, ch[0]);    for (int i = 1; i &lt; q; i++) &#123;        ans += dist(ch[i - 1], ch[i]);    &#125;    std::cout &lt;&lt; ans &lt;&lt; &#x27;\n&#x27;;&#125;

E. 我们都是小怪兽 (Rescue Qfish)推导公式发现边权每 $4$ 步循环。利用分层图思想，将每个点按时刻拆为 $4$ 层，层间连边，跑 Dijkstra 最短路即可。提供建图的代码。
for (ll i = 1; i &lt;= m; i++) &#123;    cin &gt;&gt; u &gt;&gt; v &gt;&gt; w;        ll w0 = w; //第一层是L    ll w1 = (w - 1) * quickpow(w + 1, md - 2, md) % md; //第二层是(L-1)/(L+1)    ll w2 = -quickpow(w, md - 2, md) % md;   //第三层是(-1)/L    ll w3 = (w + 1) * quickpow((1 - w + md) % md, md - 2, md) % md;//第四层是(L+1)/(1-L) 每四次循环    if (w1 &lt; 0) w1 += md;    if (w2 &lt; 0) w2 += md;    if (w3 &lt; 0) w3 += md;    g[u].push_back(&#123;w0, v + n&#125;);    g[v].push_back(&#123;w0, u + n&#125;);    g[u + n].push_back(&#123;w1, v + 2 * n&#125;);    g[v + n].push_back(&#123;w1, u + 2 * n&#125;);    g[u + 2 * n].push_back(&#123;w2, v + 3 * n&#125;);    g[v + 2 * n].push_back(&#123;w2, u + 3 * n&#125;);    g[u + 3 * n].push_back(&#123;w3, v&#125;);    g[v + 3 * n].push_back(&#123;w3, u&#125;);&#125;

F. 爱的魔力转圈圈——终极幸存者挑战赛这是一道约瑟夫环问题，但是数据开小了遍历也能过，递推公式： $\mathcal{f(n, k)=f(n-1, k)+k}$
#include &lt;iostream&gt;using namespace std;int main() &#123;    int n;    long long k;      cin &gt;&gt; n &gt;&gt; k;        long long res = 0;  // f(1)=0（1个人时位置为0）    for (int i = 2; i &lt;= n; ++i) &#123;        res = (res + k) % i;  // 递推计算f(i)    &#125;        cout &lt;&lt; res + 1 &lt;&lt; endl;  // 转换为1-based编号    return 0;&#125;

G. 探险者的补给路线直接根据题目意思写就行，$x, y$ 分别是 $a, b$ 的倍数。
void clearlove13(void)&#123;    i64 a, b, x, y;    std::cin &gt;&gt; a &gt;&gt; b &gt;&gt; x &gt;&gt; y;    if (x % a == 0 &amp;&amp; y % b == 0 &amp;&amp; x &gt;= 0 &amp;&amp; y &gt;= 0) &#123;        std::cout &lt;&lt; &quot;YES\n&quot;;    &#125; else &#123;        std::cout &lt;&lt; &quot;NO\n&quot;;    &#125;&#125;

H. Qfish的法术首先我们根据题意每次加2，可以知道区间和无论怎么操作奇偶性永远不会改变，由此延申我们进行分类讨论，如果区间长度是奇数的话，经过操作后的区间和直接贪心成偶数的目标去，因没有要求对操作后的值有具体要求，所以区间长度是奇数就一定可以，如果区间长度为偶数，但区间和为奇数，每次+2并不会改变奇偶性，所以无解。
值得注意的是，我们需要对长度为2的区间进行一个简单的特判，区间和直接用前缀和维护就行。
void clearlove13(void)&#123;    int n, t;    std::cin &gt;&gt; n &gt;&gt; t;    std::vector&lt;i64&gt;a(n + 1);    for (int i = 1; i &lt;= n; i++) &#123;        std::cin &gt;&gt; a[i];        a[i] += a[i - 1];    &#125;    while (t--) &#123;        int l, r;        std::cin &gt;&gt; l &gt;&gt; r;        if (r - l + 1 == 2 &amp;&amp; (a[r] != a[l - 1])) &#123;            std::cout &lt;&lt; &quot;NO\n&quot;;            continue;        &#125;        if (((r - l + 1LL) % 2 == 0) &amp;&amp; ((a[r] - a[l - 1]) % 2 == 1)) &#123;            std::cout &lt;&lt; &quot;NO\n&quot;;        &#125; else &#123;            std::cout &lt;&lt; &quot;YES\n&quot;;        &#125;    &#125;&#125;

I. 字母混淆直接根据题目来模拟就行。
void solve()&#123;    string s;    int n;    cin &gt;&gt; n &gt;&gt; s;    s = &quot; &quot; + s;    for (int i = 1; i &lt;= n; ++i)        cout &lt;&lt; (char)((s[i] + 32 - &#x27;a&#x27; - 2 + 26) % 26 + &#x27;a&#x27;);&#125;

J. 小s的杀戮尖塔超级大模拟， 首先我们可以观察到，观者的血量不会超过1000，并且大鄂虫每行动3轮攻击力就会永久增加，而观者每轮理想情况下只能有15点格挡。所以计算可知游戏轮数一定不会超过60轮。因此可以使用三维 $dp$ 求解。$dp_{i, j, q}$，$i$ 代表第 $i$ 轮，$j$ 代表大鄂虫剩余 $j$ 滴血，$q$ 代表观者处于的姿态。记录的是观者剩余的血量。每次抽取 $5$ 张牌，用 dfs 记录所有会到达的状态。后面就是漫长的调试代码时间，总复杂度是 $\mathcal{O(60\times b \times  3 \times 5)}$。而且题目的伤害与大鄂虫的格挡实际上都是3的倍数，因此可以把伤害与血量 $\div 3$ 进行计算。实际上由于状态数远不会到达最高复杂度，因此代码可以通过。std 的耗时约 $150ms$。 一些容易导致 WA 的细节： 

第一轮的行动 $1$ 与后面轮次的行动 $1$ 不同。后面轮次的行动 $1$ 是有 $9$ 点护甲的，第一轮没有。 
最后 $1$ 轮观者战胜大鄂虫时，游戏立即结算，此时观者不会再受到伤害。 
把费用用完并不是最优解，例如手里是 $5$ 张暴怒，此时可能会选择一张都不打。 

由于出题人的 std 过于臃肿，因此在这里放上能够通过对拍的 AI 代码。
typedef long long ll;ll dp[2][40400][3]; ll num[505050];struct MoveResult &#123;    ll dmg;        // 造成的伤害    ll self_blk;   // 获得的格挡    ll end_stance; // 结束姿态&#125;;vector&lt;MoveResult&gt; moves_cache[3]; // [起始姿态] -&gt; 结果列表int main()&#123;    cin.tie(0); cout.tie(0); ios::sync_with_stdio(0);    ll t, a, b, n;    if(!(cin &gt;&gt; t)) return 0;        while(t--)&#123;        cin &gt;&gt; a &gt;&gt; b &gt;&gt; n;        for(int i=1; i&lt;=n; i++) cin &gt;&gt; num[i];                // 压缩敌方血量        ll max_b = (b - 1) / 3 + 1;                for(int x=0; x&lt;=max_b; x++)             for(int s=0; s&lt;3; s++) dp[0][x][s] = -1;                    vector&lt;pair&lt;ll, ll&gt;&gt; q; // 队列: &#123;敌方血量, 姿态&#125;        q.push_back(&#123;max_b, 0&#125;);        dp[0][max_b][0] = a;                ll ans = -1;        ll turn = 0;        ll gong = 0; // 力量                while(!q.empty() &amp;&amp; turn &lt; 60) &#123;            ll cur = turn % 2;            ll nxt = (turn + 1) % 2;            turn++;                        // 重置下一轮DP状态            for(int x=0; x&lt;=max_b; x++)                for(int s=0; s&lt;3; s++) dp[nxt][x][s] = -1;                        // 1. 确定手牌            vector&lt;ll&gt; hand;            for(int i=0; i&lt;5; i++) &#123;                ll idx = ((turn - 1) * 5 + i) % n + 1;                hand.push_back(num[idx]);            &#125;            sort(hand.begin(), hand.end());                        // 2. 预计算所有出牌结果            for(int s=0; s&lt;3; s++) moves_cache[s].clear();                        do &#123;                for(int start_s=0; start_s&lt;3; start_s++) &#123;                    ll c = 3, cur_s = start_s;                    ll raw_dmg = 0, self_blk = 0;                                        // 记录&quot;一张牌都不出&quot;也是一种可能                    moves_cache[start_s].push_back(&#123;0, 0, start_s&#125;);                                        for(ll card : hand) &#123;                        ll cost = (card &gt;= 4) ? 2 : 1;                        if(c &lt; cost) break;                        c -= cost;                                                // 伤害计算                        ll d = 0;                        if(card == 1) d = 6;                        else if(card == 3 || card == 4) d = 9;                        if(cur_s == 1) d *= 2; // 愤怒翻倍                        raw_dmg += d;                                                // 格挡计算                        if(card == 2) self_blk += 5;                        else if(card == 5) self_blk += 8;                                                // 姿态变更                        ll old_s = cur_s;                        if(card == 3) cur_s = 0;                        else if(card == 4) cur_s = 1;                        else if(card == 5) cur_s = 2;                        if(old_s == 2 &amp;&amp; (card == 3 || card == 4)) c += 2;                                                // 存入结果 (伤害/3, 格挡, 姿态)                        moves_cache[start_s].push_back(&#123;raw_dmg / 3, self_blk, cur_s&#125;);                    &#125;                &#125;            &#125; while(next_permutation(hand.begin(), hand.end()));                        // 3. 大鄂虫属性计算            ll chong = (turn - 1) % 3 + 1;            if(turn &gt; 1 &amp;&amp; (turn - 1) % 3 == 0) gong += 5; // 每3回合加一次力量                        ll enemy_dmg = 0;            if(chong == 1) enemy_dmg = 12 + gong;            else if(chong == 2) enemy_dmg = 7 + gong;                        ll enemy_blk_reduce = 0;            if(turn &gt; 1) &#123;                ll prev_act = (turn - 2) % 3 + 1;                if(prev_act == 2) enemy_blk_reduce = 2; // 6/3                else if(prev_act == 3) enemy_blk_reduce = 3; // 9/3            &#125;                        vector&lt;pair&lt;ll, ll&gt;&gt; next_q;                        // 4. 状态转移            for(auto &amp;st : q) &#123;                ll e_hp = st.first;                ll p_stance = st.second;                ll p_hp = dp[cur][e_hp][p_stance];                                for(auto &amp;res : moves_cache[p_stance]) &#123;                    // 计算实际对敌伤害                    ll dmg_dealt = max(0LL, res.dmg - enemy_blk_reduce);                    ll next_e_hp = e_hp - dmg_dealt;                                        // 击杀判定                    if(next_e_hp &lt;= 0) &#123;                        ans = max(ans, p_hp);                        continue; // 敌死，不入队                    &#125;                                        // 玩家承伤计算                    ll incoming = enemy_dmg;                    if(res.end_stance == 1) incoming *= 2; // 愤怒易伤                    ll take = max(0LL, incoming - res.self_blk);                    ll next_p_hp = p_hp - take;                                        if(next_p_hp &gt; 0) &#123;                        if(dp[nxt][next_e_hp][res.end_stance] == -1) &#123;                            next_q.push_back(&#123;next_e_hp, res.end_stance&#125;);                            dp[nxt][next_e_hp][res.end_stance] = next_p_hp;                        &#125; else &#123;                            dp[nxt][next_e_hp][res.end_stance] = max(dp[nxt][next_e_hp][res.end_stance], next_p_hp);                        &#125;                    &#125;                &#125;            &#125;            q = next_q;        &#125;        cout &lt;&lt; ans &lt;&lt; &quot;\n&quot;;    &#125;    return 0;&#125;
